def test_open_checking_account_unverified_customer_forbidden(api_client, create_unverified_customer, assert_no_notification_sent):
    customer = create_unverified_customer()
    payload = {"customer_id": customer["id"], "initial_deposit": 1000.00}

    resp = api_client.post("/accounts/checking", json=payload)

    assert resp.status_code == 403
    assert_no_notification_sent(customer["id"], notification_type="welcome")

def test_open_checking_account_decision_table_unverified_invalid_deposit(api_client, create_unverified_customer):
    customer = create_unverified_customer()
    payload = {"customer_id": customer["id"], "initial_deposit": 10.00}

    resp = api_client.post("/accounts/checking", json=payload)

    assert resp.status_code == 403
